import React, { useState } from 'react';
import { fundApi } from '../../../services/api';

export default function DonateFundPage() {
  const [form, setForm] = useState({
    userCert: '',
    fundId: '',
    donorId: '',
    tokenId: '',
    amount: '',
  });
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState(null);

  const onChange = (e) =>
    setForm({ ...form, [e.target.name]: e.target.value });

  const onSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage(null);

    try {
      const res = await fundApi.donate(form);
      setMessage(res?.data || 'Donation successful');
    } catch (err) {
      setMessage(
        err?.response?.data?.error || err.message || 'Donation failed'
      );
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={onSubmit} style={{ maxWidth: 800, margin: '0 auto' }}>
      <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 12 }}>
        <div>
          <label>User Cert</label>
          <input
            name="userCert"
            value={form.userCert}
            onChange={onChange}
            placeholder="userCert"
            required
          />
        </div>

        <div>
          <label>Fund ID</label>
          <input
            name="fundId"
            value={form.fundId}
            onChange={onChange}
            placeholder="fundId"
            required
          />
        </div>

        <div>
          <label>Donor ID</label>
          <input
            name="donorId"
            value={form.donorId}
            onChange={onChange}
            placeholder="donorId"
            required
          />
        </div>

        <div>
          <label>Token ID</label>
          <input
            name="tokenId"
            value={form.tokenId}
            onChange={onChange}
            placeholder="tokenId"
            required
          />
        </div>

        <div>
          <label>Amount</label>
          <input
            name="amount"
            value={form.amount}
            onChange={onChange}
            placeholder="amount"
            type="number"
            required
          />
        </div>
      </div>

      <button
        type="submit"
        disabled={loading}
        style={{ marginTop: 12, width: '100%' }}
      >
        {loading ? 'Sending...' : 'Send Request'}
      </button>

      {message && <div style={{ marginTop: 12 }}>{String(message)}</div>}
    </form>
  );
}
